// Page.tsx (Server Component)
export default async function Page() {
  const data = await fetchData(); // Runs on server

  return (
    <section>
      <DataDisplay data={data} />
      <InteractiveButton> // Client Component
        Click Me
      </InteractiveButton>
    </section>
  );
}

